import queue
import time
import threading

class ConnectionPool:
    def __init__(self, factory, max_size=10, timeout=5):
        self.factory = factory
        self.max_size = max_size
        self.timeout = timeout
        self._pool = queue.Queue()
        self._count = 0
        self._lock = threading.Lock()
        self._cond = threading.Condition(self._lock)

    def get(self):
        with self._lock:
            if not self._pool.empty() or self._count < self.max_size:
                if self._pool.empty():
                    self._count += 1
                    conn = self.factory()
                    self._pool.put(conn)
                return self._pool.get()
            deadline = time.time() + self.timeout
            while self._pool.empty():
                if time.time() >= deadline:
                    raise Exception("Timeout")
                self._cond.wait(timeout=deadline - time.time())
            return self._pool.get()

    def put(self, conn):
        self._pool.put(conn)
        with self._lock:
            self._cond.notify()
